-- حذف الاختبارات الزائدة التي لا تنتمي للقائمة المعتمدة
-- أولاً: حذف الأنواع الفرعية المكررة للحديد الإنشائي (نبقي واحداً فقط)
DELETE FROM test_types WHERE code IN (
  'STEEL_STRUCT_A36', 'STEEL_STRUCT_A572', 'STEEL_STRUCT_A500',
  'STEEL_STRUCT_A501', 'STEEL_PIPE_A53', 'STEEL_STRUCT_A653',
  'STEEL_STRUCT_S275', 'STEEL_STRUCT_S355', 'STEEL_STRUCTURAL'
);

-- حذف الأنواع الفرعية المكررة للأنكر بولت (نبقي واحداً فقط)
DELETE FROM test_types WHERE code IN (
  'STEEL_ANCHOR_M12', 'STEEL_ANCHOR_M16', 'STEEL_ANCHOR_M20',
  'STEEL_ANCHOR_M24', 'STEEL_ANCHOR_M30'
);

-- حذف الأنواع الفرعية المكررة للانحناء (نبقي واحداً فقط)
DELETE FROM test_types WHERE code IN ('STEEL_BEND_BS4449', 'STEEL_BEND_ASTM');

-- حذف الأنواع الفرعية المكررة للخرسانة الرغوية (نبقي واحداً فقط)
DELETE FROM test_types WHERE code IN ('CONC_FOAM_CUBE', 'CONC_FOAM_DENSITY');

-- حذف الأنواع الفرعية المكررة للأسفلت المستخلص
DELETE FROM test_types WHERE code IN (
  'ASPH_EXTRACTED_SIEVE_ACWC', 'ASPH_EXTRACTED_SIEVE_ACBC', 'ASPH_EXTRACTED_SIEVE_DBM'
);

-- حذف الأنواع الفرعية المكررة لمعدل الرش
DELETE FROM test_types WHERE code IN (
  'ASPH_SPRAY_SS1', 'ASPH_SPRAY_SS1H', 'ASPH_SPRAY_CRS1',
  'ASPH_SPRAY_MC30', 'ASPH_SPRAY_MC70', 'ASPH_SPRAY_MC250'
);

-- حذف اختبارات الركام المكررة
DELETE FROM test_types WHERE code IN ('AGG_CRUSHING', 'AGG_IMPACT', 'AGG_LA_ABRASION');

-- حذف اختبارات الإنترلوكينج المكررة (نبقي واحداً)
DELETE FROM test_types WHERE code IN ('CONC_INTERLOCK_6', 'CONC_INTERLOCK_8');

-- حذف اختبارات البلوك المكررة (نبقي واحداً)
DELETE FROM test_types WHERE code IN ('CONC_BLOCK_SOLID', 'CONC_BLOCK_HOLLOW', 'CONC_BLOCK_THERMAL');

-- حذف اختبارات حديد التسليح المكررة (نبقي واحداً)
DELETE FROM test_types WHERE code IN ('STEEL_REBAR_BS4449', 'STEEL_REBAR_A615');

-- حذف اختبارات الركام المكررة
DELETE FROM test_types WHERE code IN (
  'AGG_SIEVE_COARSE', 'AGG_SIEVE_FINE',
  'AGG_SG_COARSE', 'AGG_SG_FINE',
  'AGG_FLAKINESS', 'AGG_ELONGATION'
);

-- حذف اختبار تدرج ركام الخلطة الخرسانية (غير موجود في القائمة المعتمدة)
DELETE FROM test_types WHERE code = 'CONC_MIX_GRAD';

-- حذف اختبار الأسمنت القديم إذا كان مكرراً
DELETE FROM test_types WHERE code = 'CEM_SETTING_TIME' AND id != (SELECT MIN(id) FROM test_types t2 WHERE t2.code = 'CEM_SETTING_TIME');

